import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

/**
 * Test for the endless loop issue with elvis operator wrapping.
 * See: https://github.com/pinterest/ktlint/issues/...
 */
class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Given a binary expression with elvis operator and long throw expression, it should not cause endless loop`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                               $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // The code should remain unchanged after formatting
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(code)
    }

    @Test
    fun `Given a binary expression with elvis operator that exceeds max line length, wrap before operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                 $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                 $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a binary expression with elvis operator with short expressions on one line, no wrapping is needed`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                 $EOL_CHAR
            val foo = bar ?: baz
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(code)
    }

    @Test
    fun `Given an elvis expression already wrapped with operator at start of line, should remain stable`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                               $EOL_CHAR
            val foo =
                bar
                    ?: baz
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .isFormattedAs(code)
    }
}"}

