            // $MAX_LINE_LENGTH_MARKER                                 $EOL_CHAR
            fun foo() = leftHandSideExpression && rightHandSideExpression
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                 $EOL_CHAR
