        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                $EOL_CHAR
            fun foo() {
                if (leftHandSideExpression && rightHandSideExpression) {
                    // do something
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                $EOL_CHAR
