            }
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ArgumentListWrappingRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .hasLintViolationWithoutAutoCorrect(3, 17, "Line is exceeding max line length")
    }

    @Test
    fun `Given a binary expression with elvis operator already on new line, should be stable`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                               $EOL_CHAR
            val foo =
                bar
                    ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .isFormattedAs(code)
    }

    @Test
    fun `Given a binary expression with elvis operator that exceeds max line length, wrap before operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                 $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                 $EOL_CHAR
            val foo =
                bar
                    ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .isFormattedAs(formattedCode)
    }
